                select = "*";
            }

            string where = req.Query["where"];
            string orderBy = req.Query["orderBy"];
            string top = req.Query["top"];

            var sql = new StringBuilder();
            sql.Append("SELECT ");

            if (!string.IsNullOrWhiteSpace(top) && int.TryParse(top, out int topValue) && topValue > 0)
            {
                sql.Append("TOP ").Append(topValue).Append(" ");
            }

            sql.Append(select)
               .Append(" FROM ")
               .Append(table);

            var conditions = new List<string>();

            foreach (var key in req.Query.Keys)
